  "$schema": "https://json.schemastore.org/claude-code-settings.json",
  "hooks": {
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "MAIN_ROOT=$(dirname \"$(git rev-parse --absolute-git-dir | sed 's|/worktrees/[^/]*$||')\") && PATH=\"$MAIN_ROOT/node_modules/.bin:$PATH\" \"$MAIN_ROOT/node_modules/.bin/nano-staged\" --unstaged --quiet --bail || exit 2",
            "statusMessage": "Running nano-staged on modified files"
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Edit|Write|MultiEdit",
        "hooks": [
          {
            "type": "command",
            "command": "npm run format",
            "statusMessage": "Formatting with prettier"
          },
          {
            "type": "command",
            "command": "npm run typecheck",
            "statusMessage": "Running typecheck"
          }
        ]
      }
    ]
  },
  "worktree": {
    "symlinkDirectories": ["node_modules"]
  }
}

